void AudioManager::PlaySound(const std::string& sound, int loops) {
    int channel = -1;
    auto found = soundEffectCache.find(sound);
    Mix_Chunk* sfx = nullptr;
    if (found != soundEffectCache.end()) {
        sfx = found->second;
        channel = findFreeChannel();
    } else {
