        sfx = Mix_LoadWAV(sound.c_str());
        if (sfx) {
            soundEffectCache[sound] = sfx;
            channel = findFreeChannel();
        }
    }

    if (channel != -1) {
        channelsUsage[channel] = true;
        Mix_PlayChannel(channel, sfx, loops);
        // Perhaps use Mix_ChannelFinished to release channels automatically
    } else {
        // Handle error: All channels are busy
    }
